#include <iostream>
#include <set>
#include <vector>

class Intset {
private:
    std::set<int> data;

public:
    // Constructor
    Intset() {}

    // Construct from vector of integers
    Intset(const std::vector<int>& values) {
        for (int val : values) {
            data.insert(val);
        }
    }

    // Add an element
    void add(int value) {
        data.insert(value);
    }

    // Remove an element
    void remove(int value) {
        data.erase(value);
    }

    // Check if element is in set
    bool contains(int value) const {
        return data.find(value) != data.end();
    }

    // Union: A + B
    Intset operator+(const Intset& other) const {
        Intset result;
        result.data = this->data;
        for (int val : other.data) {
            result.data.insert(val);
        }
        return result;
    }

    // Intersection: A * B
    Intset operator*(const Intset& other) const {
        Intset result;
        for (int val : this->data) {
            if (other.data.find(val) != other.data.end()) {
                result.data.insert(val);
            }
        }
        return result;
    }

    // Difference: A - B
    Intset operator-(const Intset& other) const {
        Intset result;
        for (int val : this->data) {
            if (other.data.find(val) == other.data.end()) {
                result.data.insert(val);
            }
        }
        return result;
    }

    // Symmetric difference: A ^ B
    Intset operator^(const Intset& other) const {
        Intset result;
        // (A - B) ∪ (B - A)
        Intset diff1 = *this - other;
        Intset diff2 = other - *this;
        result = diff1 + diff2;
        return result;
    }

    // Print the set
    void print() const {
        std::cout << "{ ";
        for (auto it = data.begin(); it != data.end(); ++it) {
            if (it != data.begin()) std::cout << ", ";
            std::cout << *it;
        }
        std::cout << " }" << std::endl;
    }
};

// Test program
int main() {
    std::vector<int> v1 = {1, 2, 3, 4};
    std::vector<int> v2 = {3, 4, 5, 6};

    Intset A(v1);
    Intset B(v2);

    std::cout << "A = "; A.print();
    std::cout << "B = "; B.print();

    Intset C = A + B;  // Union
    std::cout << "A + B = "; C.print();

    Intset D = A * B;  // Intersection
    std::cout << "A * B = "; D.print();

    Intset E = A - B;  // Difference
    std::cout << "A - B = "; E.print();

    Intset F = A ^ B;  // Symmetric difference
    std::cout << "A ^ B = "; F.print();

    return 0;
}

