enum LineType { SOLID, DASHED, DOTTED };

class Shape {
public:
    virtual ~Shape() = default;
    virtual void rotate(int degrees) = 0;
    virtual void draw() = 0;

    void setThickness(int thickValue) {
        thickness = thickValue;
        std::cout << "Setting thickness to " << thickness << std::endl;
    }

    void setLineType(LineType type) {
        lineType = type;
        std::string typeStr;
        switch (type) {
            case SOLID:   typeStr = "SOLID"; break;
            case DASHED:  typeStr = "DASHED"; break;
            case DOTTED:  typeStr = "DOTTED"; break;
        }
        std::cout << "Setting line type to " << typeStr << std::endl;
    }

protected:
    int thickness = 1;
    LineType lineType = SOLID;
};

class Circle : public Shape {
public:
    Circle() {
        std::cout << "Circle constructed." << std::endl;
    }

    Circle(double r) : radius(r) {
        std::cout << "Circle constructed with radius " << radius << "." << std::endl;
    }

    ~Circle() override {
        std::cout << "Circle destroyed." << std::endl;
    }

    void rotate(int degrees) override {
        std::cout << "Circle rotated by " << degrees << " degrees (no visual change)." << std::endl;
    }

    void draw() override {
        std::cout << "Drawing a circle with radius " << radius 
                  << ", thickness=" << thickness 
                  << ", lineType=";
        switch (lineType) {
            case SOLID:  std::cout << "SOLID"; break;
            case DASHED: std::cout << "DASHED"; break;
            case DOTTED: std::cout << "DOTTED"; break;
        }
        std::cout << std::endl;
    }

private:
    double radius = 1.0;
};

class Rectangle : public Shape {
public:
    Rectangle() {
        std::cout << "Rectangle constructed." << std::endl;
    }

    Rectangle(double w, double h) : width(w), height(h) {
        std::cout << "Rectangle constructed with width " << w << " and height " << h << "." << std::endl;
    }

    ~Rectangle() override {
        std::cout << "Rectangle destroyed." << std::endl;
    }

    void rotate(int degrees) override {
        std::cout << "Rectangle rotated by " << degrees << " degrees. New orientation applied." << std::endl;
        // Simulate rotation effect
        if ((degrees % 180) != 0) {
            double temp = width;
            width = height;
            height = temp;
        }
    }

    void draw() override {
        std::cout << "Drawing a rectangle " << width << " x " << height
                  << ", thickness=" << thickness
                  << ", lineType=";
        switch (lineType) {
            case SOLID:  std::cout << "SOLID"; break;
            case DASHED: std::cout << "DASHED"; break;
            case DOTTED: std::cout << "DOTTED"; break;
        }
        std::cout << std::endl;
    }

private:
    double width = 1.0, height = 1.0;
};

#include <iostream>
#include <vector>

int main() {
    std::vector<Shape*> shapes;

    Circle* c1 = new Circle();
    Circle* c2 = new Circle(5.0);
    Rectangle* r1 = new Rectangle(3.0, 4.0);

    shapes.push_back(c1);
    shapes.push_back(c2);
    shapes.push_back(r1);

    for (auto* shape : shapes) {
        shape->setThickness(2);
        shape->setLineType(DASHED);
        shape->draw();
        shape->rotate(90);
        std::cout << "---" << std::endl;
    }

    // Clean up
    for (auto* shape : shapes) {
        delete shape;
    }

    return 0;
}

