#include <iostream>
#include <vector>
#include <stdexcept>

// Abstract base class: Char_queue
class Char_queue {
public:
    virtual ~Char_queue() = default;

    // Pure virtual functions
    virtual void enqueue(char c) = 0;
    virtual char dequeue() = 0;
    virtual bool is_empty() const = 0;
    virtual bool is_full() const = 0;
    virtual int size() const = 0;
};

// Derived class: ListQueue using linked list
class ListQueue : public Char_queue {
private:
    struct Node {
        char data;
        Node* next;
        Node(char c) : data(c), next(nullptr) {}
    };
    Node* front;
    Node* rear;
    int count;

public:
    ListQueue() : front(nullptr), rear(nullptr), count(0) {}

    ~ListQueue() override {
        while (front) {
            Node* temp = front;
            front = front->next;
            delete temp;
        }
    }

    void enqueue(char c) override {
        Node* new_node = new Node(c);
        if (rear) {
            rear->next = new_node;
        } else {
            front = new_node;
        }
        rear = new_node;
        ++count;
    }

    char dequeue() override {
        if (is_empty()) {
            throw std::runtime_error("dequeue: queue is empty");
        }
        Node* temp = front;
        char value = front->data;
        front = front->next;
        if (!front) {
            rear = nullptr;
        }
        delete temp;
        --count;
        return value;
    }

    bool is_empty() const override {
        return front == nullptr;
    }

    bool is_full() const override {
        return false; // Linked list can grow dynamically
    }

    int size() const override {
        return count;
    }
};

// Derived class: ArrayQueue using vector
class ArrayQueue : public Char_queue {
private:
    std::vector<char> buffer;
    int capacity;
    int head;
    int tail;
    int count;

public:
    explicit ArrayQueue(int cap = 100) : capacity(cap), head(0), tail(0), count(0) {
        buffer.resize(capacity);
    }

    ~ArrayQueue() override = default;

    void enqueue(char c) override {
        if (is_full()) {
            throw std::runtime_error("enqueue: queue is full");
        }
        buffer[tail] = c;
        tail = (tail + 1) % capacity;
        ++count;
    }

    char dequeue() override {
        if (is_empty()) {
            throw std::runtime_error("dequeue: queue is empty");
        }
        char value = buffer[head];
        head = (head + 1) % capacity;
        --count;
        return value;
    }

    bool is_empty() const override {
        return count == 0;
    }

