#include <iostream>
#include <vector>
using namespace std;

class MiniQueue {
private:
    vector<int> data;

public:
    // Default constructor
    MiniQueue() {}

    // Enqueue: add element to the back
    void en_queue(int value) {
        data.push_back(value);
    }

    // Dequeue: remove element from the front
    void de_queue() {
        if (!isEmpty()) {
            data.erase(data.begin());
        }
    }

    // Access the head element (front)
    int& head() {
        return data.front();
    }

    // Check if queue is empty
    bool isEmpty() const {
        return data.empty();
    }

    // Return number of elements in queue
    int count() const {
        return data.size();
    }

    // Overload << operator to print the queue
    friend ostream& operator<<(ostream& os, const MiniQueue& q) {
        for (int val : q.data) {
            os << val << " ";
        }
        return os;
    }
};

// Test code (not part of class definition)
int main() {
    MiniQueue mq;
    for(int x = 1; x < 50; ++x) mq.en_queue(x);
    cout << mq << endl; // show all elements in queue
    while( mq.count() > 10 ) mq.de_queue();
    int & h = mq.head();
    h -= 1000; // change the element at head of queue
    cout << mq << endl; // show all data in queue

    MiniQueue mq1;
    for(int x = 1; x <= 12; ++x) mq1.en_queue(13 - x);
    cout << mq1 << endl; // show all data in queue

    MiniQueue mq2;
    while( mq1.isEmpty() == false ) {
        int tmp = mq1.head() + 1;
        mq2.en_queue(tmp);
        mq1.de_queue();
        cout << mq2 << endl;  // show all data in queue
    }

    return 0;
}

