#include <iostream>
using namespace std;

template<typename T>
class Stack {
private:
    static const int MAX_SIZE = 100;
    T data[MAX_SIZE];
    int topIndex;

public:
    Stack() : topIndex(-1) {}

    bool isEmpty() const {
        return topIndex == -1;
    }

    bool isFull() const {
        return topIndex == MAX_SIZE - 1;
    }

    void push(const T& value) {
        if (isFull()) {
            cout << "Error: Stack full!\n";
            return;
        }
        data[++topIndex] = value;
    }

    void pop() {
        if (isEmpty()) {
            cout << "Error: Stack empty!\n";
            return;
        }
        --topIndex;
    }

    T top() const {
        if (isEmpty()) {
            throw runtime_error("Stack empty!");
        }
        return data[topIndex];
    }
};

int main() {
    Stack<int> s;
    s.push(10);
    s.push(20);
    cout << s.top() << endl; // Output: 20
    s.pop();
    cout << s.top() << endl; // Output: 10
    s.pop();
    s.pop(); // Error message
    return 0;
}

