Implement a Queue class that can output the messages shown in the following program’s comments, where a queue is a First In, First Out list of zero or more elements.
（Do not change main() in any way）
Queue q;
--q;                   // Display：The queue is empty!
q = q + 5 + 6 + 3;
cout << q;              // Display：5   6   3
cout << --q << endl;      // Display：5
cout << q;             // Display：6   3
q = 9 + q;
cout << q;             // Display：6   3   9
q = 2 + q;              // Display：The queue is full!
cout << q;             // Display：6   3   9
return 0;

answer:
#include <iostream>
using namespace std;

class Queue {
private:
    static const int MAX = 100;
    int data[MAX];
    int front, rear, count;

public:
    Queue() : front(0), rear(0), count(0) {}

    // Overload prefix decrement: dequeue and return the removed element
    int operator--() {
        if (count == 0) {
            cout << "The queue is empty!" << endl;
            return -1; // dummy value, not used
        }
        int val = data[front];
        front = (front + 1) % MAX;
        count--;
        return val;
    }

    // Overload += for enqueue
    Queue& operator+=(int value) {
        if (count >= MAX) {
            cout << "The queue is full!" << endl;
            return *this;
        }
        data[rear] = value;
        rear = (rear + 1) % MAX;
        count++;
        return *this;
    }

    // Overload + to allow chaining: create a new queue, add value
    Queue operator+(int value) {
        Queue temp = *this;
        temp += value;
        return temp;
    }

    // Overload assignment from int (used in 9 + q)
    friend Queue operator+(int value, Queue& q) {
        Queue temp = q;
        temp += value;
        return temp;
    }

    // Overload output operator
    friend ostream& operator<<(ostream& os, const Queue& q) {
        if (q.count == 0) {
            return os;
        }
        int index = q.front;
        for (int i = 0; i < q.count; i++) {
            os << q.data[index] << "   ";
            index = (index + 1) % MAX;
        }
        return os;
    }
};

int main() {
    Queue q;
    --q;                   // Display：The queue is empty!
    q = q + 5 + 6 + 3;
    cout << q;              // Display：5   6   3
    cout << --q << endl;      // Display：5
    cout << q;             // Display：6   3
    q = 9 + q;
    cout << q;             // Display：6   3   9
    q = 2 + q;              // Display：The queue is full!
    cout << q;             // Display：6   3   9
    return 0;
}

