选择C++中的基本类型之一（如int类型），为它定义一个包装的类（如Integer）。该类型以操作符形式为用户提供对应基本类型上的若干运算，以及向其他基本类型转换的操作。例如
C = A + B;  ++B;  C--;
A * B / C;  A *= B;
cout << “A=” << A ;

answer:
#include <iostream>
using namespace std;

class Integer {
private:
    int value;

public:
    // 构造函数
    Integer(int v = 0) : value(v) {}

    // 前置递增
    Integer& operator++() {
        ++value;
        return *this;
    }

    // 后置递增
    Integer operator++(int) {
        Integer temp(*this);
        ++value;
        return temp;
    }

    // 前置递减
    Integer& operator--() {
        --value;
        return *this;
    }

    // 后置递减
    Integer operator--(int) {
        Integer temp(*this);
        --value;
        return temp;
    }

    // 加法运算符
    Integer operator+(const Integer& other) const {
        return Integer(value + other.value);
    }

    // 减法运算符
    Integer operator-(const Integer& other) const {
        return Integer(value - other.value);
    }

    // 乘法运算符
    Integer operator*(const Integer& other) const {
        return Integer(value * other.value);
    }

    // 除法运算符
    Integer operator/(const Integer& other) const {
        if (other.value == 0) {
            throw runtime_error("Division by zero!");
        }
        return Integer(value / other.value);
    }

    // 复合赋值运算符
    Integer& operator+=(const Integer& other) {
        value += other.value;
        return *this;
    }

    Integer& operator-=(const Integer& other) {
        value -= other.value;
        return *this;
    }

    Integer& operator*=(const Integer& other) {
        value *= other.value;
        return *this;
    }

    Integer& operator/=(const Integer& other) {
        if (other.value == 0) {
            throw runtime_error("Division by zero!");
        }
        value /= other.value;
        return *this;
    }

    // 类型转换：转为int
    operator int() const {
        return value;
    }

    // 输出友元函数
    friend ostream& operator<<(ostream& os, const Integer& obj) {
        os << obj.value;
        return os;
    }
};

