void findChar(const char cpString[], const char cChar)
{
    for (int i = 0; cpString[i] != '\0'; i++)
    {
        if (cpString[i] == cChar) {
            printf("The index is %d.\n", i);
            return;
        }
    }
    printf("In the string \"%s\" having %d char's, no '%c' has been found.\n", 
           cpString, i, cChar);
}

void find2Char(const char* cpString, const char cChar)
{
    const char* p = cpString;
    while (*p != '\0')
    {
        if (*p == cChar) {
            printf("The index is %ld.\n", p - cpString);
            return;
        }
        p++;
    }
    printf("In the string \"%s\" having %ld char's, no '%c' has been found.\n", 
           cpString, p - cpString, cChar);
}

