class MyString {
private:
    char* str;
    int len;

public:
    // 构造函数：从C风格字符串构造
    MyString(const char* s = "") {
        len = strlen(s);
        str = new char[len + 1];
        strcpy(str, s);
    }

    // 构造函数：创建指定长度的空格字符串
    MyString(int n) {
        len = n;
        str = new char[len + 1];
        for (int i = 0; i < len; ++i)
            str[i] = ' ';
        str[len] = '\0';
    }

    // 拷贝构造函数
    MyString(const MyString& other) {
        len = other.len;
        str = new char[len + 1];
        strcpy(str, other.str);
    }

    // 析构函数
    ~MyString() {
        delete[] str;
    }

    // 赋值操作符
    MyString& operator=(const MyString& other) {
        if (this != &other) {
            delete[] str;
            len = other.len;
            str = new char[len + 1];
            strcpy(str, other.str);
        }
        return *this;
    }

    // 下标操作符：返回从位置pos开始的子串
    MyString operator[](int pos) const {
        if (pos < 0 || pos >= len) return MyString("");
        int newLen = len - pos;
        char* temp = new char[newLen + 1];
        strcpy(temp, str + pos);
        MyString result(temp);
        delete[] temp;
        return result;
    }

    // 后置自增操作符：去掉首字符，返回原字符串
    MyString operator++(int) {
        MyString old(*this);  // 保存当前值
        if (len > 0) {
            char* newStr = new char[len];
            strcpy(newStr, str + 1);
            delete[] str;
            str = newStr;
            --len;
        }
        return old;
    }

    // 显示函数
    void display() const {
        cout << '<' << str << '>' << endl;
    }
};

