    // 析构函数
    ~MyString() {
        delete[] str;
    }

    // 赋值操作符
    MyString& operator=(const MyString& other) {
        if (this != &other) {
            delete[] str;
            len = other.len;
            str = new char[len + 1];
            strcpy(str, other.str);
        }
        return *this;
    }

    // 下标操作符：返回从位置pos开始的子串
    MyString operator[](int pos) const {
        if (pos < 0 || pos >= len) return MyString("");
        int newLen = len - pos;
        char* temp = new char[newLen + 1];
        strcpy(temp, str + pos);
        MyString result(temp);
        delete[] temp;
        return result;
    }

    // 后置自增操作符：去掉首字符，返回原字符串
    MyString operator++(int) {
        MyString old(*this);  // 保存当前值
        if (len > 0) {
            char* newStr = new char[len];
            strcpy(newStr, str + 1);
            delete[] str;
            str = newStr;
            --len;
        }
        return old;
    }

    // 显示函数
    void display() const {
        cout << '<' << str << '>' << endl;
    }
};

