#include <iostream>
#include <string>
using namespace std;

class Fighter {
protected:
    string name;

public:
    Fighter(const string& n) : name(n) {}

    virtual void outTitle() {
        cout << "We are fighters." << endl;
    }

    virtual void hello() {
        cout << name << " is a fighter." << endl;
    }

    virtual ~Fighter() {}
};

class Warrior : public Fighter {
private:
    Fighter* rival;

public:
    Warrior(const string& n, Fighter* r) : Fighter(n), rival(r) {}

    void hello() {
        cout << name << " is a stronger warrior than " << static_cast<Fighter*>(rival)->name << "." << endl;
    }
};

int main() {
    Fighter* objs[2];
    Warrior Stallone("Stallone", objs[0]);
    objs[0] = new Fighter("Harry");
    objs[1] = &Stallone;

    cout << "== Test the class famliy ==" << endl;
    for (int i = 0; i < 2; i++) {
        objs[i]->outTitle();
        cout << "----  " << i+1 << "  ----" << endl;
        objs[i]->hello();
    }
    cout << "==This is the end." << endl;
    delete objs[0];
    return 0;
}

